import json
import boto3
import requests

s3 = boto3.client('s3')

def lambda_handler(event, context):
    # Get the URL from the X-Enrich-URL header
    url = event['headers']['X-Enrich-URL']
    
    # Make an HTTP request to fetch the data
    response = requests.get(url)
    
    # Parse the JSON response and extract the relevant information
    data = json.loads(response.text)
    
    # Add the enriched data to the event object
    event['enriched_data'] = data
    
    # Forward the event to the origin
    return {
        'statusCode': 200,
        'body': json.dumps(event)
    }